// EB Garamond (latin) embutida em base64 para o PDF de assinatura.
// O html2canvas mede o texto errado quando a fonte vem por @import externo
// (palavras grudadas). Embutida, ela está disponível na hora da captura.
export const FONT_FACE_EBGARAMOND = `@font-face{font-family:'EB Garamond';font-style:italic;font-weight:400;font-display:block;src:url(data:font/woff2;base64,) format('woff2')}@font-face{font-family:'EB Garamond';font-style:normal;font-weight:400;font-display:block;src:url(data:font/woff2;base64,) format('woff2')}@font-face{font-family:'EB Garamond';font-style:normal;font-weight:600;font-display:block;src:url(data:font/woff2;base64,) format('woff2')}`;
